import { Link } from 'react-router-dom';
import { FaExternalLinkAlt, FaCalendarAlt } from 'react-icons/fa';

function SchemeCard({ scheme }) {
  // Format date if available
  const formatDate = (dateString) => {
    if (!dateString) return 'No deadline';
    
    const options = { year: 'numeric', month: 'short', day: 'numeric' };
    return new Date(dateString).toLocaleDateString(undefined, options);
  };

  return (
    <div className="bg-white p-6 rounded-lg shadow-md mb-4 border border-gray-200 hover:shadow-lg transition-shadow">
      <Link to={`/schemes/${scheme._id}`}>
        <h3 className="text-xl font-semibold text-blue-700 mb-2">{scheme.schemeName}</h3>
      </Link>
      
      <div className="mb-4">
        <h4 className="font-semibold text-gray-700 mb-1">Eligibility:</h4>
        <p className="text-gray-600">
          {scheme.eligibility.length > 100
            ? `${scheme.eligibility.substring(0, 100)}...`
            : scheme.eligibility}
        </p>
      </div>
      
      <div className="mb-4">
        <h4 className="font-semibold text-gray-700 mb-1">Benefits:</h4>
        <p className="text-gray-600">
          {scheme.benefits.length > 100
            ? `${scheme.benefits.substring(0, 100)}...`
            : scheme.benefits}
        </p>
      </div>
      
      <div className="flex justify-between items-center text-sm mt-4">
        {scheme.department && (
          <div className="bg-blue-100 text-blue-800 px-3 py-1 rounded-full">
            {scheme.department}
          </div>
        )}
        
        <div className="flex items-center text-gray-500">
          <FaCalendarAlt className="mr-1" />
          <span>Deadline: {formatDate(scheme.deadline)}</span>
        </div>
        
        {scheme.applicationLink && (
          <a 
            href={scheme.applicationLink} 
            target="_blank" 
            rel="noopener noreferrer"
            className="flex items-center text-blue-600 hover:underline"
          >
            Apply <FaExternalLinkAlt className="ml-1 text-xs" />
          </a>
        )}
      </div>
    </div>
  );
}

export default SchemeCard;
